func statusToGlyph(status string) (string, color.Color) {
	switch status {
	case "complete":
		return "✓", ColorFoam
	case "running":
		return "●", ColorIris
	case "failed":
		return "✗", ColorLove
	case "closed", "done":
		return "✓", ColorFoam
	default:
		return "○", ColorMuted
	}
}

